The Factory Pattern
Semantic CMR requires per-trial similarity matrices (since each list has different items). The factory pattern handles this:


Code
class CMRModelFactory:
    def __init__(self, dataset, features):
        # Pre-compute similarity matrices for all trials
        self.trial_connections = build_trial_connections(
            dataset["pres_itemids"], features
        )

    def create_trial_model(self, trial_index, parameters):
        # Create model with trial-specific similarity matrix
        return CMR(
            list_length,
            parameters,
            connections=self.trial_connections[trial_index],
            ...
        )

MemorySearchModelFactory Protocol
Model factories create model instances for specific trials.

Definition


Code
@runtime_checkable
class MemorySearchModelFactory(Protocol):
    def __init__(
        self,
        dataset: RecallDataset,
        features: Optional[Float[Array, " word_pool_items features_count"]],
    ) -&gt; None:
        """Initialize the factory with trial data."""

    def create_model(
        self,
        parameters: Mapping[str, Float_],
    ) -&gt; MemorySearch:
        """Create a generic model instance."""

    def create_trial_model(
        self,
        trial_index: Integer[Array, ""],
        parameters: Mapping[str, Float_],
    ) -&gt; MemorySearch:
        """Create a model configured for a specific trial."""


The create_trial_model method allows trial-specific configuration (e.g., different list lengths, trial-specific features like EEG data).

Component Architecture
All evaluation components follow protocols defined in jaxcmr/typing.py:


Code
# Loss function generator creates trial-specific loss functions
class LossFnGenerator(Protocol):
    def __call__(
        self,
        trial_indices: Int[Array, "trials"],
        parameters: dict[str, Array],
        free_param_names: list[str],
    ) -&gt; Callable[[Float[Array, "params"]], Float[Array, ""]]: ...

# Fitting algorithm finds optimal parameters
class FittingAlgorithm(Protocol):
    def fit(
        self,
        trial_mask: Bool[Array, "subjects trials"],
    ) -&gt; FitResult: ...


